#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#include "../common.h"
#include "../util/timer/timer.h"

extern "C" __global__ void kernel_gpu_cuda_wrapper(record *records,
										long records_mem,
										knode *knodes,
										long knodes_elem,
										long knodes_mem,
										int order,
										long maxheight,
										int count,
										long *currKnode,
										long *offset,
										int *keys,
										record *ans)
{
	int bid = blockIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = order < 1024 ? order : 1024;

	for (int i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		long off = offset[bid];
		for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
			if ((knodes[curr].keys[thid] <= keys[bid]) && (knodes[curr].keys[thid + 1] > keys[bid])) {
				if (knodes[off].indices[thid] < knodes_elem) {
					offset[bid] = knodes[off].indices[thid];
				}
			}
		}
		__syncthreads();
		currKnode[bid] = offset[bid];
	}

	long curr = currKnode[bid];
	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (knodes[curr].keys[thid] == keys[bid]) {
			ans[bid].value = records[knodes[curr].indices[thid]].value;
		}
	}
}

extern "C" void kernel_cpu(	int cores_arg,
					record *records,
					knode *knodes,
					long knodes_elem,
					int order,
					long maxheight,
					int count,
					long *currKnode,
					long *offset,
					int *keys,
					record *ans)
{
	long long time0;
	long long time1;
	long long time2;

	time0 = get_time();

	int threadsPerBlock = order < 1024 ? order : 1024;

	time1 = get_time();

	record *d_records;
	knode *d_knodes;
	long *d_currKnode;
	long *d_offset;
	int *d_keys;
	record *d_ans;

	cudaMalloc((void**)&d_records, sizeof(record)*knodes_elem);
	cudaMalloc((void**)&d_knodes, sizeof(knode)*knodes_elem);
	cudaMalloc((void**)&d_currKnode, sizeof(long)*count);
	cudaMalloc((void**)&d_offset, sizeof(long)*count);
	cudaMalloc((void**)&d_keys, sizeof(int)*count);
	cudaMalloc((void**)&d_ans, sizeof(record)*count);

	cudaMemcpy(d_records, records, sizeof(record)*knodes_elem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_knodes, knodes, sizeof(knode)*knodes_elem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_currKnode, currKnode, sizeof(long)*count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_offset, offset, sizeof(long)*count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_keys, keys, sizeof(int)*count, cudaMemcpyHostToDevice);
	cudaMemcpy(d_ans, ans, sizeof(record)*count, cudaMemcpyHostToDevice);

	kernel_gpu_cuda_wrapper<<<count, threadsPerBlock>>>(d_records, knodes_elem * sizeof(record), d_knodes, knodes_elem, knodes_elem * sizeof(knode), order, maxheight, count, d_currKnode, d_offset, d_keys, d_ans);
	cudaDeviceSynchronize();

	cudaMemcpy(ans, d_ans, sizeof(record)*count, cudaMemcpyDeviceToHost);

	cudaFree(d_records);
	cudaFree(d_knodes);
	cudaFree(d_currKnode);
	cudaFree(d_offset);
	cudaFree(d_keys);
	cudaFree(d_ans);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time2 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time2 - time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

