extern "C" __global__ void kernel_gpu_cuda_wrapper_2(	knode *knodes,
											long knodes_elem,
											long knodes_mem,
											int order,
											long maxheight,
											int count,
											long *currKnode,
											long *offset,
											long *lastKnode,
											long *offset_2,
											int *start,
											int *end,
											int *recstart,
											int *reclength)
{
	int bid = blockIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = order < 1024 ? order : 1024;

	for (int i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		long last = lastKnode[bid];
		for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
			if ((knodes[curr].keys[thid] <= start[bid]) && (knodes[curr].keys[thid + 1] > start[bid])) {
				if (knodes[curr].indices[thid] < knodes_elem) {
					offset[bid] = knodes[curr].indices[thid];
				}
			}
			if ((knodes[last].keys[thid] <= end[bid]) && (knodes[last].keys[thid + 1] > end[bid])) {
				if (knodes[last].indices[thid] < knodes_elem) {
					offset_2[bid] = knodes[last].indices[thid];
				}
			}
		}
		__syncthreads();
		currKnode[bid] = offset[bid];
		lastKnode[bid] = offset_2[bid];
	}

	long curr = currKnode[bid];
	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (knodes[curr].keys[thid] == start[bid]) {
			recstart[bid] = knodes[curr].indices[thid];
		}
	}

	long last = lastKnode[bid];
	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (knodes[last].keys[thid] == end[bid]) {
			reclength[bid] = knodes[last].indices[thid] - recstart[bid] + 1;
		}
	}
}

